private struct DiscordTabHost<Content: View>: View {
    let title: String
    let icon: String
    @ViewBuilder var content: () -> Content
    var body: some View { content() }
}

private enum DiscordScreenFactory {
    @ViewBuilder
    static func screen(for tab: String) -> some View {
        switch tab.lowercased() {
        case let t where t.contains("chat") || t.contains("message"):
            DiscordChatsScreen()
        case let t where t.contains("call") || t.contains("phone"):
            DiscordCallsScreen()
        case let t where t.contains("setting"):
            DiscordSettingsScreen()
        default:
            DiscordGenericListScreen(title: tab)
        }
    }
}
